proof fn phi_1_lemma_write_seq_read_external_body(mem: PTMem, writes: Seq<(usize, usize)>, i: int)
    requires
        0 <= i < writes.len(),
        forall|j| #![auto] 0 <= j < writes.len() && writes[j].0 == writes[i].0 ==> i == j,
    ensures
        mem.write_seq(writes).mem[writes[i].0] == writes[i].1,
{
    mem.lemma_write_seq_read(writes, i);
}

proof fn phi_3_writer_read_from_sbuf_chains_external(state: State, c: Constants, i: int)
    requires
        state.wf(c),
        state.inv_sbuf_facts(c),
        0 <= i < state.writer_sbuf().len(),
    ensures
        state.writer_mem().read(state.writer_sbuf()[i].0) == state.writer_sbuf()[i].1,
{
    lemma_writer_read_from_sbuf(state, c, i);
}
